let texto = $input.item.json.text || "";

let minuta = "No se pudo extraer el texto de la minuta.";
let data_json = {};

if (texto.includes("---MINUTA---")) {
    const partes = texto.split("---MINUTA---")[1];
    if (partes.includes("---JSON---")) {
        minuta = partes.split("---JSON---")[0].trim();
    } else {
        minuta = partes.trim();
    }
} else if (texto.trim() !== "") {
    minuta = texto.split("---JSON---")[0].trim();
}

if (texto.includes("---JSON---")) {
    let json_str = texto.split("---JSON---")[1].trim();
    if (json_str.includes("```json")) {
        json_str = json_str.split("```json")[1].split("```")[0].trim();
    } else if (json_str.includes("```")) {
        const match = json_str.match(/```(?:json)?\s*([\s\S]*?)```/);
        if (match) {
            json_str = match[1].trim();
        } else {
            json_str = json_str.split("```")[1].split("```")[0].trim();
        }
    }
    try {
        data_json = JSON.parse(json_str);
    } catch (e) {
        data_json = { "error": "No se pudo parsear JSON", "error_msg": e.message, "raw_text_extracted": json_str };
    }
}

return { "minuta": minuta, "json": data_json, "raw_llm_text": texto };
